alter table store_good_purchase_item comment '商品采购明细表';


-- ----------------------------
-- Table structure for store_goods
-- ----------------------------
DROP TABLE IF EXISTS `store_goods`;
CREATE TABLE `store_goods`  (
  `goods_id` mediumint(8) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '商品id',
  `goods_sn` varchar(60) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL DEFAULT '' COMMENT '商品编号',
  `goods_name` varchar(120) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL DEFAULT '' COMMENT '商品名称',
  `market_price` decimal(10, 2) UNSIGNED NOT NULL DEFAULT 0.00 COMMENT '市场价',
  `shop_price` decimal(10, 2) UNSIGNED NOT NULL DEFAULT 0.00 COMMENT '本店价',
  `goods_remark` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL DEFAULT '' COMMENT '商品简单描述',
  `goods_content` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '商品详细描述',
  `goods_logo` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL DEFAULT '' COMMENT '商品上传原始图(主图)',
  `is_on_sale` tinyint(1) UNSIGNED NOT NULL DEFAULT 1 COMMENT '是否上架 0-未上架 1-销售中',
  `is_recommend` tinyint(1) UNSIGNED NOT NULL DEFAULT 0 COMMENT '是否推荐0-未推荐 1-已推荐',
  `is_new` tinyint(1) UNSIGNED NOT NULL DEFAULT 0 COMMENT '是否新品0-不是 1-是',
  `goods_type` smallint(5) UNSIGNED NOT NULL DEFAULT 0 COMMENT '商品所属类型id，取值表goods_type的id',
  `spec_type` smallint(5) NULL DEFAULT 0 COMMENT '商品规格类型，取值表goods_type的id',
  `demo_url` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '演示地址',
  `sort` smallint(4) UNSIGNED NOT NULL DEFAULT 50 COMMENT '商品排序',
  PRIMARY KEY (`goods_id`) USING BTREE,
  INDEX `goods_sn`(`goods_sn`) USING BTREE,
  INDEX `sort_order`(`sort`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 11 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '商品主表' ROW_FORMAT = Compact;

-- ----------------------------
-- Records of store_goods
-- ----------------------------
INSERT INTO `store_goods` VALUES (10, '1', '模块化快速开发框架', 788.00, 88.00, 'Java快速开发解决方案', '<div style=\"text-align: center; margin: 15px 0 25px 0;\"><span style=\"padding: 10px 15px; border-top: 2px solid #3EC483; border-bottom: 2px solid #3EC483; display: inline-block; font-size: 16px; color: #555;\"> 规格说明</span></div>\n<div>\n<table class=\"layui-table\"><colgroup><col width=\"120px\" /><col /></colgroup>\n<tbody>\n<tr>\n<th style=\"background-color: #f4f7f7; color: #333; text-align: right;\">基础版：</th>\n<td>集成基础权限管理功能:包括用户管理、角色管理、菜单管理、 部门管理、岗位管理，字典管理等众多基础功能和模块; 完全遵循Java开发规范, 简洁易懂, 开箱即用, 是毕设、个人站点以及入门学习的首选产品。</td>\n</tr>\n<tr>\n<th style=\"background-color: #f4f7f7; color: #333; text-align: right;\">专业版：</th>\n<td>专业版除了包含基础版所有功能外，还集成了定制的代码生成器模块, 可一键正向和逆向生成代码，无需手写代码以及多余配置, 减少99%开发工作量, 为您节约更多时间，去陪恋人、家人和朋友。</td>\n</tr>\n<tr>\n<th style=\"background-color: #f4f7f7; color: #333333; text-align: right;\">旗舰版:&nbsp;&nbsp;</th>\n<td>旗舰版包含专业版所有功能, 另外提供在线智能工作流模块, 适合有复杂流程的业务系统，同时, 配合在线布局和在线代码生成器, 能极大缩短流程开发时间, 减少 流程业务系统开发复杂度, 节省人力成本。</td>\n</tr>\n</tbody>\n</table>\n</div>\n<div style=\"font-size: 15px; line-height: 30px; padding: 5px;\">\n<p>授权时长说明：</p>\n<p>&emsp;&emsp;在授权有效期内您可以不限次下载代码，版本更新后可以免费升级新版本，可以查看授权版本的开发文档，可以加入技术服务群享受售后服务及技术支持， 授权过期后，不再提供下载功能，不能查看开发文档，不再提供售后服务及技术支持，但是您可以继续使用之前版本的框架开发项目， 授权过期后您也可以再次授权延长授权期。</p>\n</div>\n<div style=\"padding: 15px 20px; border-left: 4px solid #3ec483; margin-top: 20px; font-size: 14px;\"><span style=\"color: #333333;\"> 在线演示地址：</span><a style=\"color: #397b21;\" href=\"http://demo.javaboot.cn\" target=\"_blank\" rel=\"noopener\">http://demo.javaboot.cn</a></div>\n<div style=\"text-align: center; margin: 15px 0 35px 0;\"><span style=\"padding: 10px 15px; border-top: 2px solid #3EC483; border-bottom: 2px solid #3EC483; display: inline-block; font-size: 16px; color: #555;\"> 项目截图</span></div>\n<p><img src=\"http://47.104.26.199:8082/profile/upload/2020/04/21/770050f1ee90a5cdcc805bca4f22c22d.png\" /></p>\n<p>&nbsp;</p>\n<p><img src=\"http://47.104.26.199:8082/profile/upload/2020/04/21/0588e438ce3b114b961ed77e89b2ea9e.png\" /></p>\n<p>&nbsp;</p>\n<p><img src=\"http://47.104.26.199:8082/profile/upload/2020/04/21/5555e0385fef017d32151eb929525878.png\" /></p>\n<p>&nbsp;</p>\n<p><img src=\"http://47.104.26.199:8082/profile/upload/2020/04/21/2972af5f6f558f9393cea6bc0b23d470.png\" /></p>\n<p>&nbsp;</p>\n<p><img src=\"http://47.104.26.199:8082/profile/upload/2020/04/21/dbddb2cf71bb6225d9dc0df73792a578.png\" /></p>', '2020/04/24/1587738535116.jpg', 1, 1, 1, 41, 0, 'http://demo.javaboot.cn', 1);

-- ----------------------------
-- Table structure for store_goods_classify
-- ----------------------------
DROP TABLE IF EXISTS `store_goods_classify`;
CREATE TABLE `store_goods_classify`  (
  `classify_id` varchar(100) NOT NULL COMMENT '分类编号',
  `name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '名称',
  `another_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '别称',
  `level` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '级别',
  `unit` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '数量单位',
  `parent_id` varchar(100) NULL DEFAULT NULL COMMENT '上级id',
  `sort` int(4) NULL DEFAULT NULL COMMENT '排序',
  `status` varchar(2) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '状态:0删除,1正常',
  `create_time` timestamp(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) COMMENT '创建时间',
  `last_modify_time` timestamp(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) COMMENT '最后更新时间',
  PRIMARY KEY (`classify_id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '商品分类表' ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for store_goods_coupon
-- ----------------------------
DROP TABLE IF EXISTS `store_goods_coupon`;
CREATE TABLE `store_goods_coupon`  (
  `coupon_id` int(8) NOT NULL COMMENT '优惠券id',
  `goods_id` int(11) NOT NULL DEFAULT 0 COMMENT '指定的商品id：为零表示不指定商品',
  PRIMARY KEY (`coupon_id`, `goods_id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = latin1 COLLATE = latin1_swedish_ci COMMENT = '优惠券与商品关联表' ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for store_goods_quotation
-- ----------------------------
DROP TABLE IF EXISTS `store_goods_quotation`;
CREATE TABLE `store_goods_quotation`  (
  `quotation_id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '报价单id',
  `dept_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '区域id',
  `quotation_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '报价单名称',
  `start_time` varchar(30) NOT NULL COMMENT '定价开始时间',
  `end_time` varchar(30) NOT NULL COMMENT '定价结束时间',
  `operate_start_time` varchar(30) NOT NULL COMMENT '运营结束时间',
  `operate_end_time` varchar(30) NOT NULL COMMENT '运营结束时间',
  `quotation_abbreviation` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '报价单简称(对外)',
  `description` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '描述',
  `status` varchar(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '0-删除 1-未激活 2-已激活',
  `create_time` timestamp(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) COMMENT '创建时间',
  `last_modify_time` timestamp(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) COMMENT '最后更新时间',
  PRIMARY KEY (`quotation_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '报价信息表' ROW_FORMAT = Compact;

drop table if exists store_goods_quotation_goods;

/*==============================================================*/
/* Table: store_goods_quotation_goods                           */
/*==============================================================*/
create table store_goods_quotation_goods
(
   goods_id             bigint not null auto_increment comment '商品id',
   quotation_id         bigint comment '报价单id',
   spu_no               varchar(50) comment '商品spu',
   unit_ids             varchar(100) comment '销售单位id',
   price                numeric(10,2) comment '单价',
   property_name        varchar(200) comment '属性名称',
   goods_subtitle       varchar(200) comment '商品副标题',
   goods_introduce      text comment '商品介绍',
   level                varchar(2) comment '所属商户等级',
   merchant_id          bigint comment '所属商户id',
   status               varchar(1) comment '状态:0-删除，1上架，2-下架',
   sale_num             decimal(10,2) COMMENT  '报价单商品上数库存',
   sale_percent         decimal(10,2) COMMENT  '报价单商品上数设置比率',
   `url` varchar(255) DEFAULT NULL COMMENT '商品图片',
   create_time          timestamp default CURRENT_TIMESTAMP comment '创建时间',
   last_modify_time     timestamp default CURRENT_TIMESTAMP comment '最后更新时间',
   primary key (goods_id)
);

alter table store_goods_quotation_goods comment '报价单商品表（由金蝶衍生出来的商品）';

drop table if exists store_goods_sales_unit;

/*==============================================================*/
/* Table: store_goods_sales_unit                                */
/*==============================================================*/
create table store_goods_sales_unit
(
   unit_id              bigint not null auto_increment comment '单位id',
   name                 varchar(30) comment '销售单位',
   settlement_unit      varchar(30) comment '结算单位',
   conversion_relationship numeric(10,2) comment '换算关系',
   order_num            int(4) default 0 comment '排序',
   status               varchar(1) default '1' comment '状态：0-删除,1-启用,2-禁用',
   create_time          timestamp default CURRENT_TIMESTAMP comment '创建时间',
   last_modify_time     timestamp default CURRENT_TIMESTAMP comment '最后更新时间',
   primary key (unit_id),
   key AK_Key_1 (unit_id)
);

alter table store_goods_sales_unit comment '销售单位表';




