CREATE TABLE `store_house`  (
  `store_id` bigint(20) NOT NULL AUTO_INCREMENT,
  `store_no` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '仓库编号',
