  `dept_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '所属区域',
  `store_type` varchar(2) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '仓库类型',
  `status` varchar(2) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '1' COMMENT '状态：0-删除，1-正常',
  `create_time` timestamp(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) COMMENT '创建时间',
  `last_modify_time` timestamp(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) ON UPDATE CURRENT_TIMESTAMP(0) COMMENT '最后更新时间',
  PRIMARY KEY (`store_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for store_member
-- ----------------------------
DROP TABLE IF EXISTS `store_member`;
CREATE TABLE `store_member` (
  `id` int(20) unsigned NOT NULL AUTO_INCREMENT,
  `customer_no` varchar(10) DEFAULT '' COMMENT 'vip编号',
  `openid_qq` varchar(255) DEFAULT NULL COMMENT '会员QQ OPENID',
  `openid_wx` varchar(255) DEFAULT '' COMMENT '会员微信OPENID',
  `phone` varchar(16) DEFAULT '' COMMENT '会员手机号',
  `password` varchar(64) DEFAULT '' COMMENT '登录密码',
  `nickname` varchar(20) DEFAULT '' COMMENT '会员昵称',
  `headimg` varchar(500) DEFAULT '' COMMENT '会员头像',
  `sex` char(2) DEFAULT '' COMMENT '性别',
  `level` varchar(20) DEFAULT '1' COMMENT '会员级别：普通、中级、高级',
  `email` varchar(255) DEFAULT NULL COMMENT '邮箱',
  `address` varchar(255) DEFAULT NULL COMMENT '所在城市/地址',
  `signature` varchar(500) DEFAULT '' COMMENT '个性签名',
  `total_amount` decimal(10,2) unsigned DEFAULT '0.00' COMMENT '消费累计额度 用于用户等级',
  `user_money` decimal(8,2) DEFAULT '0.00' COMMENT '用户金额',
  `distribut_money` decimal(8,2) unsigned DEFAULT '0.00' COMMENT '累积分佣金额',
  `frozen_money` double(8,2) unsigned DEFAULT '0.00' COMMENT '冻结金额',
  `underling_number` int(5) unsigned DEFAULT '0' COMMENT '用户下线总数',
  `pay_points` int(8) unsigned DEFAULT '0' COMMENT '消费积分',
  `address_id` int(10) unsigned DEFAULT '0' COMMENT '默认收货地址',
  `status` tinyint(1) unsigned DEFAULT '0' COMMENT '会员状态0待审核 1-已审核 2-已拒绝',
  `remark` varchar(500) DEFAULT NULL COMMENT '备注',
  `create_time` datetime DEFAULT NULL,
  `create_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `status_time` bigint(20) unsigned DEFAULT '0' COMMENT '审核时间',
  `customer_area` varchar(100) DEFAULT NULL COMMENT '客户区域',
  `creditcode` varchar(255) DEFAULT NULL COMMENT '信用证代码',
  `customer_class` varchar(255) DEFAULT NULL COMMENT '客户分类',
  `customer_type` varchar(255) DEFAULT NULL COMMENT '客户类别：社区门店、电商平台、大客户、批发',
  `super_customer` varchar(255) DEFAULT NULL COMMENT '客户所属(上级)',
  `billing_cusotmer` varchar(255) DEFAULT NULL COMMENT '结算客户',
  `card_number` varchar(255) DEFAULT NULL COMMENT '身份证号码',
  `receive_address` varchar(500) DEFAULT NULL COMMENT '收货地址',
  `customer_kinds` varchar(255) DEFAULT NULL COMMENT '客户类型',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=69 DEFAULT CHARSET=utf8 ROW_FORMAT=COMPACT COMMENT='商城会员信息';

-- ----------------------------
-- Records of store_member
-- ----------------------------

-- ----------------------------
-- Table structure for store_order
-- ----------------------------
DROP TABLE IF EXISTS `store_order`;
CREATE TABLE `store_order`  (
  `order_id` mediumint(8) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '订单id',
  `order_sn` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL DEFAULT '' COMMENT '订单编号',
  `user_id` varchar(100) NOT NULL DEFAULT 0 COMMENT '用户id',
  `order_status` tinyint(1) UNSIGNED NOT NULL DEFAULT 0 COMMENT '订单状态 0-未确认 1-已确认(已收货） 2-已评价',
  `pay_status` tinyint(1) UNSIGNED NOT NULL DEFAULT 0 COMMENT '支付状态 0-未支付 1-已支付',
  `pay_method` tinyint(1) UNSIGNED NOT NULL DEFAULT 2 COMMENT '支付方式1-微信 2-支付宝 3-余额 4-转账',
  `pay_name` varchar(120) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL DEFAULT '' COMMENT '支付方式名称',
  `coupon_price` decimal(10, 2) NULL DEFAULT 0.00 COMMENT '优惠券抵扣',
  `order_amount` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT '应付款金额',
  `total_amount` decimal(10, 2) NULL DEFAULT 0.00 COMMENT '订单总价',
  `add_time` datetime(0) NOT NULL COMMENT '下单时间',
  `pay_time` datetime(0) NULL DEFAULT NULL COMMENT '支付时间',
  `deleted` tinyint(1) NOT NULL DEFAULT 0 COMMENT '用户假删除标识,1:删除,0未删除',
  `goods_id` int(11) NULL DEFAULT NULL COMMENT '商品ID',
  `goods_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '商品名称',
  `spec_key` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '商品规格key',
  `spec_key_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '规格对应的中文名字',
  `spec_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '商品规格中文名',
  `auth_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '授权时长中文名',
  `expiration_time` datetime(0) NULL DEFAULT NULL COMMENT '到期时间',
  PRIMARY KEY (`order_id`) USING BTREE,
  UNIQUE INDEX `order_sn`(`order_sn`) USING BTREE,
  INDEX `user_id`(`user_id`) USING BTREE,
  INDEX `add_time`(`add_time`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1884 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '订单主表' ROW_FORMAT = Compact;

