-- ----------------------------
-- Table structure for store_route_shop
-- ----------------------------
DROP TABLE IF EXISTS `store_route_shop`;
CREATE TABLE `store_route_shop`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '自增id',
  `route_id` bigint(20) NOT NULL COMMENT '线路id',
  `customer_id` bigint(20) NOT NULL COMMENT '商户id',
  `sequence_no` int(4) NULL DEFAULT NULL COMMENT '配送顺序',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '线路和商户关联表' ROW_FORMAT = Compact;

-- ----------------------------
-- Table structure for store_sale_setting
-- ----------------------------
DROP TABLE IF EXISTS `store_sale_setting`;
CREATE TABLE `store_sale_setting`  (
  `setting_id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '上数id',
  `dept_id` varchar(100) NOT NULL COMMENT '区域id',
  `spu_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '商品SPU',
  `quanintiy` decimal(10, 2) NOT NULL COMMENT '昨日库存数量',
  `in_quanintiy` decimal(10, 2) NOT NULL COMMENT '在途数量',
  `ready_quanintiy` decimal(10, 2) NOT NULL COMMENT '到货数量',
  `specifications` varchar(2) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '上数商品规格',
  `self_quanintiy` decimal(10, 2) NOT NULL COMMENT '浮动数量',
  `setting_quanintiy` decimal(10, 2) NOT NULL COMMENT '上数数量',
  `status` varchar(1) NOT NULL DEFAULT '1' COMMENT '状态 0-删除 1-正常',
  `create_time` timestamp(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) COMMENT '创建时间',
  `last_modify_time` timestamp(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) COMMENT '最后更新时间',
  PRIMARY KEY (`setting_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '商品上数设置表' ROW_FORMAT = Compact;

-- ----------------------------
