DROP TABLE IF EXISTS `store_source`;
CREATE TABLE `store_source`  (
  `id` int(20) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `version` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '版本',
  `down_url` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '源码下载地址',
  `goods_id` int(20) NULL DEFAULT NULL COMMENT '商品ID',
  `spec_id` int(20) NULL DEFAULT NULL COMMENT '规格ID',
  `spec_item_id` int(20) NULL DEFAULT NULL COMMENT '规格项ID',
  `create_time` datetime(0) NULL DEFAULT NULL COMMENT '创建时间',
  `update_time` datetime(0) NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 6 CHARACTER SET = utf8 COLLATE = utf8_general_ci ROW_FORMAT = Compact;

