drop table if exists store_warehouse_inventory;

/*==============================================================*/
/* Table: store_warehouse_inventory                             */
/*==============================================================*/
create table store_warehouse_inventory
(
   inventory_id         bigint not null auto_increment comment '盘库id',
   inventory_no         varchar(100) not null comment '盘点编号',
   warehouse_id         bigint not null comment '仓库id',
   dept_id              varchar(100) not null comment '区域id',
   creator_id           varchar(100) not null comment '操作者',
   quantity             numeric(10,2) not null comment '盘点总数量',
   lonely_number        numeric(10,2) not null comment '盘点只数',
   amount               numeric(10,2) not null comment '盘点总金额',
   intentory_date       date not null comment '盘点日期',
   intentory_src_id     bigint comment '上期盘库id',
   status               varchar(1) comment '0-删除 1-正常',
   create_time          timestamp default CURRENT_TIMESTAMP comment '创建时间',
   last_modify_time     timestamp default CURRENT_TIMESTAMP comment '最后更新时间',
   primary key (inventory_id)
);

alter table store_warehouse_inventory comment '商品盘库表';

drop table if exists store_warehouse_inventory_item;

/*==============================================================*/
/* Table: store_warehouse_inventory_item                        */
/*==============================================================*/
create table store_warehouse_inventory_item
(
   item_id              bigint not null auto_increment comment '明细id',
   inventory_id         bigint not null comment '盘库id',
   spu_no               varchar(100) not null comment '商品SPU',
   change_type          varchar(2) comment '变动类型:0-报损,1-报溢',
   unit                 varchar(20)  comment '单位',
   stock_lonely_quantity numeric(10,2) comment '库存只数',
   stock_quantity       numeric(10,2) comment '库存数量',
   inventory_quantity   numeric(10,2) comment '盘点数量',
   inventory_lonely_quantity   numeric(10,2) comment '盘点只数',
   initial_inventory_cost numeric(10,2)  comment '初始库存成本',
   storage_amount       numeric(10,2)  comment '入库金额',
   inventory_status     varchar(2) comment '盘点状态:0-盘亏,1-盘赢',
   inventory_result     numeric(10,2)  comment '盘点结果',
   sales_amount         numeric(10,2) comment '销售金额',
   sales_quantity       numeric(10,2) comment '销售数量',
   sales_lonely_quantity  numeric(10,2) comment '销售只数',
   remaining_quantity   numeric(10,2) comment '剩余数量',
   status               varchar(1) comment '状态:0-删除 1-正常',
   price               numeric(10,2) comment '盘点后单价',
   create_time          timestamp default CURRENT_TIMESTAMP comment '创建时间',
   last_modify_time     timestamp default CURRENT_TIMESTAMP comment '最后更新时间',
   primary key (item_id)
);

alter table store_warehouse_inventory_item comment '商品盘库明细表';

-- ----------------------------
-- Table structure for store_warehouse_stock
-- ----------------------------
DROP TABLE IF EXISTS `store_warehouse_stock`;
CREATE TABLE `store_warehouse_stock`  (
  `stock_id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '入库id',
  `stock_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '入库单编号',
  `warehouse_id` bigint(20) NOT NULL COMMENT '仓库id',
  `supplier_id` varchar(200) NOT NULL COMMENT '供应商id',
  `dept_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '区域id',
  `stock_type` varchar(2) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '仓库类别1-商品 2-物料',
    status               varchar(1) comment '0-删除 1-正常',
    `category` varchar(2) NOT NULL DEFAULT '1' COMMENT '入库类别：1-正常入库,2-退货入库',
  `create_time` timestamp(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) COMMENT '创建时间',
  `last_modify_time` timestamp(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) COMMENT '最后更新时间',
  PRIMARY KEY (`stock_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '商品入库表' ROW_FORMAT = Compact;

drop table if exists store_warehouse_stock_item;

/*==============================================================*/
/* Table: store_warehouse_stock_item                            */
/*==============================================================*/
create table store_warehouse_stock_item
(
   item_id              bigint not null auto_increment comment '入库明细id',
   stock_id             bigint not null comment '入库id',
   spu_no               varchar(100) not null comment '商品SPU',
   warehouse_id         bigint not null comment '仓库id',
   quantity             numeric(10,2) not null comment '库存数量',
   stocks_number        numeric(10,2) comment '库存只数',
   amount               numeric(10,2) not null comment '入库金额',
   quantity_unit        varchar(50) comment '数量单位',
   weight_unit          varchar(50) comment '重量单位',
      status               varchar(1) comment '0-删除 1-正常',
   create_time          timestamp default CURRENT_TIMESTAMP comment '创建时间',
   last_modify_time     timestamp default CURRENT_TIMESTAMP comment '最后更新时间',
   primary key (item_id)
);

alter table store_warehouse_stock_item comment '商品入库表明细表';






-- ----------------------------
-- Table structure for sys_config
-- ----------------------------
DROP TABLE IF EXISTS `sys_config`;
CREATE TABLE `sys_config`  (
  `config_id` int(5) NOT NULL AUTO_INCREMENT COMMENT '参数主键',
  `config_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '' COMMENT '参数名称',
  `config_key` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '' COMMENT '参数键名',
  `config_value` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '' COMMENT '参数键值',
  `config_type` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT 'N' COMMENT '系统内置（Y是 N否）',
  `create_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '' COMMENT '创建者',
  `create_time` datetime(0) NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '' COMMENT '更新者',
  `update_time` datetime(0) NULL DEFAULT NULL COMMENT '更新时间',
  `remark` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  PRIMARY KEY (`config_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 18 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '参数配置表' ROW_FORMAT = Compact;

