-- ----------------------------
-- View structure for act_id_group
-- ----------------------------
DROP VIEW IF EXISTS `act_id_group`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `act_id_group` AS select `r`.`role_key` AS `ID_`,NULL AS `REV_`,`r`.`role_name` AS `NAME_`,'assignment' AS `TYPE_` from `sys_role` `r`;

-- ----------------------------
-- View structure for act_id_membership
-- ----------------------------
DROP VIEW IF EXISTS `act_id_membership`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `act_id_membership` AS select (select `u`.`login_name` from `sys_user` `u` where (`u`.`user_id` = `ur`.`user_id`)) AS `USER_ID_`,(select `r`.`role_key` from `sys_role` `r` where (`r`.`role_id` = `ur`.`role_id`)) AS `GROUP_ID_` from `sys_user_role` `ur`;

-- ----------------------------
-- View structure for act_id_user
-- ----------------------------
DROP VIEW IF EXISTS `act_id_user`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `act_id_user` AS select `u`.`login_name` AS `ID_`,0 AS `REV_`,`u`.`user_name` AS `FIRST_`,'' AS `LAST_`,`u`.`email` AS `EMAIL_`,`u`.`password` AS `PWD_`,'' AS `PICTURE_ID_` from `sys_user` `u`;

-- ----------------------------
-- Function structure for getChildLst
-- ----------------------------
DROP FUNCTION IF EXISTS `getChildLst`;
delimiter ;;
CREATE FUNCTION `getChildLst`(rootId INT)
 RETURNS varchar(1000) CHARSET utf8mb4
BEGIN
        DECLARE sTemp VARCHAR(1000); 
        DECLARE sTempChd VARCHAR(1000); 
 
        SET sTemp = '^'; 
        SET sTempChd =cast(rootId as CHAR); 
 
        WHILE sTempChd is not null DO 
            SET sTemp = concat(sTemp,',',sTempChd); 
            SELECT group_concat(menu_id) INTO sTempChd FROM sys_menu where FIND_IN_SET(parent_id,sTempChd)>0; 
        END WHILE; 
        RETURN sTemp; 
END
;;
delimiter ;

SET FOREIGN_KEY_CHECKS = 1;





DROP TABLE IF EXISTS store_goods_order;

CREATE TABLE store_goods_order
(
    order_id             BIGINT NOT NULL AUTO_INCREMENT COMMENT '订单id',
    merchant_id          VARCHAR(100) NOT NULL COMMENT '客户id',
    dept_id              VARCHAR(100) COMMENT '区域id',
    code                 VARCHAR(100) COMMENT '订单编号',
    price                DECIMAL(10,2) NOT NULL COMMENT '订单金额', -- 建议用 DECIMAL 代替 NUMERIC
    source               VARCHAR(2) NOT NULL COMMENT '订单来源1-微信 2-代客下单',
    print_status         VARCHAR(2) NOT NULL COMMENT '0-未打印 1-已打印',
    pay_status           VARCHAR(2) NOT NULL COMMENT '0-未付款 1-已付款',
    status               VARCHAR(2) NOT NULL COMMENT '0-删除 1-待审核 2-待分拣 3-已分拣  4-已完成 5-已作废',
    old_status           VARCHAR(2) DEFAULT NULL COMMENT '原状态',
    receipt_status       VARCHAR(2) NOT NULL DEFAULT '0' COMMENT '付款单生成状态0-未生成1-已生成',
    comment              TEXT COMMENT '订单备注',
    delivery_date        TIMESTAMP NULL COMMENT '交货日期',
    receive_date         TIMESTAMP NULL COMMENT '收货日期',
    warehouse_id         BIGINT COMMENT '仓库id',
    financial_audit_status VARCHAR(2) NOT NULL DEFAULT '0' COMMENT '财务审核状态:0-待审核,1-审核未支付',
    syn_status           VARCHAR(2) NOT NULL DEFAULT '0' COMMENT '订单同步EAS状态:0-待同步,1-已同步',
    create_time          TIMESTAMP DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
    last_modify_time     TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '最后更新时间', -- 优化：增加了自动更新
    PRIMARY KEY (order_id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='订单信息主表'; -- 修复：注释移到这里



