/*==============================================================*/
create table store_black_white
(
   black_white_id       bigint not null auto_increment comment 'id',
   `account_id` varchar(100) NOT NULL COMMENT '账户id',
   merchant_id          varchar(100) not null comment '客户id',
   dept_id              varchar(100) not null comment '区域id',
