drop table if exists store_payment_account;
CREATE TABLE `store_payment_account` (
  `account_id` varchar(100) NOT NULL COMMENT '账户ID',
  `member_id` varchar(100) NOT NULL COMMENT '商户id',
  `dept_id` varchar(100) DEFAULT NULL COMMENT '区域id',
  `account_number` varchar(100) DEFAULT NULL COMMENT '账户号',
  `bill_days` int DEFAULT 1 COMMENT '账单周期',
  `store_id` varchar(100) DEFAULT NULL COMMENT '所属门店',
  `cash` decimal(10,2) NOT NULL DEFAULT 0.0 COMMENT '现金账户',
  `status` varchar(1) DEFAULT NULL COMMENT '0-删除 1-启用 2-禁用',
  `rebate_account` decimal(10,2) NOT NULL DEFAULT 0.0  COMMENT '返点账户',
  `bond_account` decimal(10,2) NOT NULL DEFAULT 0.0  COMMENT '保证金账户',
  `create_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `last_modify_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '最后更新时间',
  PRIMARY KEY (`account_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='支付账户';

