CREATE TABLE `store_account_flow` (
  `flow_id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '流水ID',
    `account_id` varchar(100) NOT NULL COMMENT '账户id',
  `account_number` varchar(100) DEFAULT NULL COMMENT '账户号',
  `type` varchar(2) DEFAULT NULL COMMENT '操作类型：0-预付，1-充值',
