/*==============================================================*/
create table store_sorting_performance_month
(
   id                   bigint(20) not null auto_increment comment '自增id',
   user_id              varchar(100) not null comment '用户id',
   dept_id              varchar(100) not null comment '区域id',
   sorting_month        varchar(20) not null comment '分拣月份：2020-07',
   result               decimal(10,2) not null comment '绩效结果',
   operator_id          varchar(100) not null comment '核算人员id',
   status               varchar(2) not null default '1' comment '状态：0-删除，1-正常',
   create_time          timestamp default CURRENT_TIMESTAMP comment '创建时间',
   last_modify_time     timestamp default CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP comment '最后更新时间',
   primary key (id)
);

