drop table if exists store_payment_flow;
/*==============================================================*/
/* Table: store_payment_flow                                 */
/*==============================================================*/
create table store_payment_flow
(
   id                bigint not null auto_increment comment '流水id',
   pay_order_no      varchar(64) not null comment '传给招行的订单号，订单号+随机数',
   receipt_id          bigint not null comment '付款单id',
   order_ids          varchar(500) not null comment '订单id列表',
   cmb_order_no      varchar(64)  comment '招行生成的订单号',
   qr_code           varchar(300)  comment '二维码地址',
   status            varchar(2) default '1' comment '0-删除 1-正常',
   return_code       varchar(32)  comment 'SUCCESS/FAIL,此字段是通信标识，非交易标识，交易是否成功需要查看respCode来判断。SUCCESS表示商户上送的报文符合规范，FAIL表示报文内的字段不符合规范，包括长度超长、非法字符、签名错误等',
   resp_code         varchar(32)  comment '招行返回的业务错误码，成功为SUCCESS，失败为FAIL，若此时errCode为SYSTERM_ERROR则表示本次请求处理异常，并非交易结果是失败状态，需要商户再次发起查询确认',
   rsp_txt           text comment '二维码返回的报文体',
   qry_rsp_txt           text comment '查询结果返回的报文体',
   trade_state       varchar(32) comment 'C - 订单已关闭 D - 交易已撤销 P - 交易在进行 F - 交易失败 S - 交易成功 R - 转入退款',
   create_time          timestamp default CURRENT_TIMESTAMP comment '创建时间',
   last_modify_time     timestamp default CURRENT_TIMESTAMP comment '最后更新时间',
   primary key (id)
);
alter table store_payment_flow comment '聚合支付流水表';

